import jsonfrom pathlib import Path# =====================================================# تحديد المسار# =====================================================# هذا الملف موجود داخل:# bot/services/storage.py# لذلك نطلع مجلدين حتى نوصل لـ bot/BASE_DIR = Path(__file__).resolve().parent.parent# ملف قاعدة البياناتDB_FILE = BASE_DIR / "data" / "listings.json"# =====================================================# تحميل البيانات# =====================================================def load_data():    """    قراءة ملف listings.json وإرجاع البيانات.    إذا الملف غير موجود → إنشاء ملف فارغ تلقائياً.    """    if not DB_FILE.exists():        DB_FILE.parent.mkdir(parents=True, exist_ok=True)        default_data = {"info": {}, "categories": {}}        save_data(default_data)        return default_data    with open(DB_FILE, "r", encoding="utf-8") as f:        return json.load(f)# =====================================================# حفظ البيانات# =====================================================def save_data(data):    """    حفظ البيانات داخل listings.json بشكل منسق.    """    DB_FILE.parent.mkdir(parents=True, exist_ok=True)    with open(DB_FILE, "w", encoding="utf-8") as f:        json.dump(data, f, ensure_ascii=False, indent=2)